// supabase/functions/email-assets/index.ts
//
// Public, cacheable host for transactional-email images (currently the brand
// logo). Decoupled from the frontend deploy so emails always have a working
// absolute https URL. verify_jwt = false: serves a static public asset and
// processes no user input. Logo bytes are embedded (base64) to keep this
// self-contained and avoid a Storage dependency.

export {}; // mark as an ES module

const LOGO_PNG_BASE64 = "";

function bytesFromBase64(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

const LOGO_BYTES = bytesFromBase64(LOGO_PNG_BASE64);

Deno.serve((req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, HEAD, OPTIONS",
      },
    });
  }
  if (req.method !== "GET" && req.method !== "HEAD") {
    return new Response("Method not allowed", { status: 405 });
  }
  return new Response(req.method === "HEAD" ? null : LOGO_BYTES, {
    status: 200,
    headers: {
      "Content-Type": "image/png",
      "Cache-Control": "public, max-age=31536000, immutable",
      "Access-Control-Allow-Origin": "*",
    },
  });
});
